import CoreData

func performMigration(persistentStoreCoordinator: NSPersistentStoreCoordinator) throws {
    let modelURL = Bundle.main.url(forResource: "DataModel", withExtension: "momd")!
    let sourceModel = NSManagedObjectModel(contentsOf: modelURL)!

    // Get the destination model
    let destinationModel = NSManagedObjectModel.mergedModel(from: [sourceModel])

    let migrationOptions = [NSMigratePropertyMapKey: [
        "name": "name"
    ]]

    let migration = NSManagedObjectMigration(sourceModel: sourceModel, destinationModel: destinationModel, migrationOptions: migrationOptions)

    let storeURL = NSPersistentStoreCoordinator.defaultURLForType(NSSQLiteStoreType)

    do {
        try migration.migrateStore(from: storeURL, to: storeURL, options: nil)
        print("Migration successful!")
    } catch {
        print("Migration failed: \(error)")
        throw error
    }
}
```
