import StoreKit

class ProductManager: ObservableObject {
    @Published var products: [Product] = []
    let productIDs = ["com.example.app.premiumfeature"] // Replace with your product IDs

    init() {
        fetchProducts()
    }

    func fetchProducts() {
        let request = ProductRequest(productIdentifiers: productIDs)
        request.delegate = self
        request.start()
    }

    func purchaseProduct(product: Product) {
        if let transaction = try? Transaction(product: product) {
            StoreKit.requestPurchase(for: transaction) {
                result in
                switch result {
                case .success: print("Purchase successful!")
                case .failure(let error): print("Purchase failed: \(error)")
                }
            }
        }
    }

    func restorePurchases() {
        StoreKit.restorePurchases() {
            result in
            switch result {
            case .success: print("Restore successful!")
            case .failure(let error): print("Restore failed: \(error)")
            }
        }
    }
}

extension ProductManager: ProductRequestDelegate {
    func productRequest(_ request: ProductRequest, didRetrieve products: [Product]) {
        self.products = products
    }

    func productRequest(_ request: ProductRequest, didFailWithError error: Error) {
        print("Failed to retrieve products: \(error)")
    }
}
```
