import SwiftUI

struct AnimatedCircle: View {
    @State private var scale: CGFloat = 1.0
    @State private var rotation: Double = 0.0
    @State private var color: Color = .red

    var body: some View {
        Circle()
            .fill(color)
            .frame(width: 100 * scale, height: 100 * scale)
            .rotationEffect(.degrees(rotation))
            .modifier(AnimatableModifier(scale: scale, rotation: rotation, color: color))
            .onAppear {
                withAnimation(.easeInOut(duration: 2).repeatForever(autoreverses: true)) {
                    scale = 2.0
                }
                withAnimation(.easeInOut(duration: 3).repeatForever(autoreverses: true)) {
                    rotation += 360.0
                }
                withAnimation(.easeInOut(duration: 4).repeatForever(autoreverses: true)) {
                    color = Array(range(in: 0...5)).map { Color.init(red: Double.random(in: 0...1), green: Double.random(in: 0...1), blue: Double.random(in: 0...1))}[Int(scale * 2) % 6]
                }
            }
    }
}

struct AnimatableModifier: ViewModifier {
    let scale: CGFloat
    let rotation: Double
    let color: Color

    func body(content: Content) -> some View {
        content
            .scaleEffect(scale)
            .rotationEffect(.degrees(rotation))
            .foregroundColor(color)
    }
}


struct ContentView: View {
    @State private var showCircle = false

    var body: some View {
        VStack {
            if showCircle {
                AnimatedCircle()
                    .transition(.scale)
            }
            Button("Toggle Circle") {
                withAnimation {
                    showCircle.toggle()
                }
            }
        }
    }
}
```
Giải thích: `AnimatableModifier` cho phép chúng ta thay đổi các thuộc tính của view một cách mượt mà. `withAnimation` được sử dụng để tạo hiệu ứng chuyển động khi view xuất hiện và biến mất, cũng như thay đổi các thuộc tính của hình tròn.  `repeatForever(autoreverses: true)` tạo ra một animation lặp đi lặp lại, thay đổi hướng sau mỗi lần lặp.

